import React, { useRef, useState } from 'react';

const COLORS = ['#111827', '#dc2626', '#16a34a', '#2563eb', '#d97706'];

export default function DrawingBoard() {
  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const [color, setColor] = useState('#111827');
  const [size, setSize] = useState(4);

  const pos = (e) => {
    const r = canvasRef.current.getBoundingClientRect();
    return [e.clientX - r.left, e.clientY - r.top];
  };

  const start = (e) => {
    drawing.current = true;
    const c = canvasRef.current.getContext('2d');
    const [x, y] = pos(e);
    c.beginPath();
    c.moveTo(x, y);
  };

  const move = (e) => {
    if (!drawing.current) return;
    const c = canvasRef.current.getContext('2d');
    c.strokeStyle = color;
    c.lineWidth = size;
    c.lineCap = 'round';
    c.lineJoin = 'round';
    const [x, y] = pos(e);
    c.lineTo(x, y);
    c.stroke();
  };

  const end = () => {
    drawing.current = false;
  };

  const clear = () => {
    const cv = canvasRef.current;
    cv.getContext('2d').clearRect(0, 0, cv.width, cv.height);
  };

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 10 }}>
        {COLORS.map((c) => (
          <button
            key={c}
            onClick={() => setColor(c)}
            aria-label={c}
            style={{ width: 26, height: 26, borderRadius: '50%', background: c, border: color === c ? '3px solid #111' : '1px solid #ccc', cursor: 'pointer' }}
          />
        ))}
        <label style={{ fontSize: 13 }}>
          Size {size}
          <input type="range" min="1" max="24" value={size} onChange={(e) => setSize(Number(e.target.value))} />
        </label>
        <button onClick={clear} style={{ padding: '6px 12px', cursor: 'pointer' }}>Clear</button>
      </div>
      <canvas
        ref={canvasRef}
        width={420}
        height={280}
        onPointerDown={start}
        onPointerMove={move}
        onPointerUp={end}
        onPointerLeave={end}
        style={{ border: '1px solid #cbd5e1', borderRadius: 8, touchAction: 'none', cursor: 'crosshair', background: '#fff' }}
      />
    </div>
  );
}

