import { Component, ViewChild, ElementRef } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-drawing-board',
  template: `
    <div>
      <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 10px;">
        <button
          *ngFor="let c of colors"
          (click)="color = c"
          [attr.aria-label]="c"
          [style.background]="c"
          [style.border]="color === c ? '3px solid #111' : '1px solid #ccc'"
          style="width: 26px; height: 26px; border-radius: 50%; cursor: pointer;"
        ></button>
        <label style="font-size: 13px;">Size {{ size }}
          <input type="range" min="1" max="24" [value]="size" (input)="size = toNum($any($event.target).value)" />
        </label>
        <button (click)="clear()" style="padding: 6px 12px; cursor: pointer;">Clear</button>
      </div>
      <canvas
        #cv
        width="420"
        height="280"
        (pointerdown)="start($event)"
        (pointermove)="move($event)"
        (pointerup)="end()"
        (pointerleave)="end()"
        style="border: 1px solid #cbd5e1; border-radius: 8px; touch-action: none; cursor: crosshair; background: #fff;"
      ></canvas>
    </div>
  `,
})
export class DrawingBoardComponent {
  @ViewChild('cv') cv!: ElementRef<HTMLCanvasElement>;
  colors = ['#111827', '#dc2626', '#16a34a', '#2563eb', '#d97706'];
  color = '#111827';
  size = 4;
  private drawing = false;

  toNum(v: string): number {
    return Number(v);
  }

  ctx(): CanvasRenderingContext2D {
    return this.cv.nativeElement.getContext('2d') as CanvasRenderingContext2D;
  }

  pos(e: PointerEvent): number[] {
    const r = this.cv.nativeElement.getBoundingClientRect();
    return [e.clientX - r.left, e.clientY - r.top];
  }

  start(e: PointerEvent): void {
    this.drawing = true;
    const c = this.ctx();
    const p = this.pos(e);
    c.beginPath();
    c.moveTo(p[0], p[1]);
  }

  move(e: PointerEvent): void {
    if (!this.drawing) {
      return;
    }
    const c = this.ctx();
    c.strokeStyle = this.color;
    c.lineWidth = this.size;
    c.lineCap = 'round';
    c.lineJoin = 'round';
    const p = this.pos(e);
    c.lineTo(p[0], p[1]);
    c.stroke();
  }

  end(): void {
    this.drawing = false;
  }

  clear(): void {
    const cv = this.cv.nativeElement;
    this.ctx().clearRect(0, 0, cv.width, cv.height);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Drawing Board Demo</h1>
      <app-drawing-board></app-drawing-board>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, DrawingBoardComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
